 10â†’/**
 11â†’ * Marks declarations in the datetime library that use format strings to define datetime formats.
 12â†’ *
 13â†’ * Format strings are discouraged, because they require gaining proficiency in another tiny language.
 14â†’ * When possible, please use the builder-style Kotlin API instead.
 15â†’ * If the format string is a constant, the corresponding builder-style Kotlin code can be obtained by calling
 16â†’ * [DateTimeFormat.formatAsKotlinBuilderDsl] on the resulting format. For example:
 17â†’ * ```
 18â†’ * DateTimeFormat.formatAsKotlinBuilderDsl(LocalTime.Format { byUnicodePattern("HH:mm") })
 19â†’ * ```
 20â†’ */
 21â†’@MustBeDocumented
 22â†’@Retention(value = AnnotationRetention.BINARY)
 23â†’@RequiresOptIn(
 24â†’    level = RequiresOptIn.Level.WARNING,
 25â†’    message = "Using format strings is discouraged." +
 26â†’            " If the format string is a constant, the corresponding builder-style Kotlin code can be obtained by calling" +
 27â†’            " `DateTimeFormat.formatAsKotlinBuilderDsl` on the resulting format."
 28â†’)
 29â†’public annotation class FormatStringsInDatetimeFormats
 30â†’
 31â†’/**
 32â†’ * Appends a Unicode date/time format string to the [DateTimeFormatBuilder].
 33â†’ *
 34â†’ * This is the format string syntax used by the Java Time's `DateTimeFormatter` class, Swift's and Objective-C's
 35â†’ * `NSDateFormatter` class, and the ICU library.
 36â†’ * The syntax is specified at
 37â†’ * <https://unicode-org.github.io/icu/userguide/format_parse/datetime/#datetime-format-syntax>.
 38â†’ *
 39â†’ * Currently, locale-aware directives are not supported, due to no locale support in Kotlin.
 40â†’ *
 41â†’ * In addition to the standard syntax, this function also supports the following extensions:
 42â†’ * * `[]` denote optional sections. For example, `hh:mm[:ss]` will allow parsing seconds optionally.
 43â†’ *   This is similar to what is supported by the Java Time's `DateTimeFormatter` class.
 44â†’ *
 45â†’ * Usage example:
 46â†’ * ```
 47â†’ * DateTimeComponents.Format {
 48â†’ *   // 2023-01-20T23:53:16.312+03:30[Asia/Tehran]
 49â†’ *   byUnicodePattern("uuuu-MM-dd'T'HH:mm[:ss[.SSS]]xxxxx'['VV']'")
 50â†’ * }
 51â†’ * ```
 52â†’ *
 53â†’ * The list of supported directives is as follows:
 54â†’ *
 55â†’ * | **Directive**       | **Meaning**                                                                             |
 56â†’ * | `'string'`          | literal `string`, without quotes                                                        |
 57â†’ * | `'''`               | literal char `'`                                                                        |
 58â†’ * | `[fmt]`             | equivalent to `fmt` during formatting, but during parsing also accepts the empty string |
 59â†’ * | `u`                 | ISO year without padding                                                                |
 60â†’ * | `uu`                | last two digits of the ISO year, with the base year 2000                                |
 61â†’ * | `uuuu`              | ISO year, zero-padded to four digits                                                    |
 62â†’ * | `M`, `L`            | month number (1-12), without padding                                                    |
 63â†’ * | `MM`, `LL`          | month number (01-12), zero-padded to two digits                                         |
 64â†’ * | `d`                 | day-of-month (1-31), without padding                                                    |
 65â†’ * | `H`                 | hour-of-day (0-23), without padding                                                     |
 66â†’ * | `HH`                | hour-of-day (00-23), zero-padded to two digits                                          |
 67â†’ * | `m`                 | minute-of-hour (0-59), without padding                                                  |
 68â†’ * | `mm`                | minute-of-hour (00-59), zero-padded to two digits                                       |
 69â†’ * | `s`                 | second-of-hour (0-59), without padding                                                  |
 70â†’ * | `ss`                | second-of-hour (00-59), zero-padded to two digits                                       |
 71â†’ * | `S`, `SS`, `SSS`... | fraction-of-second without a leading dot, with as many digits as the format length      |
 72â†’ * | `VV`                | timezone name (for example, `Europe/Berlin`)                                            |
 73â†’ *
 74â†’ * The UTC offset is formatted using one of the following directives. In every one of these formats, hours, minutes,
 75â†’ * and seconds are zero-padded to two digits. Also, hours are unconditionally present.
 76â†’ * 
 77â†’ * | **Directive**          | **Minutes** | **Seconds** | **Separator** | **Representation of zero** |
 78â†’ * | `X`                    | unless zero | never       | none          | `Z`                        |
 79â†’ * | `XX`                   | always      | never       | none          | `Z`                        |
 80â†’ * | `XXX`                  | always      | never       | colon         | `Z`                        |
 81â†’ * | `XXXX`                 | always      | unless zero | none          | `Z`                        |
 82â†’ * | `XXXXX`, `ZZZZZ`       | always      | unless zero | colon         | `Z`                        |
 83â†’ * | `x`                    | unless zero | never       | none          | `+00`                      |
 84â†’ * | `xx`, `Z`, `ZZ`, `ZZZ` | always      | never       | none          | `+0000`                    |
 85â†’ * | `xxx`                  | always      | never       | colon         | `+00:00`                   |
 86â†’ * | `xxxx`                 | always      | unless zero | none          | `+0000`                    |
 87â†’ * | `xxxxx`                | always      | unless zero | colon         | `+00:00`                   |
 88â†’ *
 89â†’ * Additionally, because the `y` directive is very often used instead of `u`, they are taken to mean the same.
 90â†’ * This may lead to unexpected results if the year is negative: `y` would always produce a positive number, whereas
 91â†’ * `u` may sometimes produce a negative one. For example:
 92â†’ * ```
 93â†’ * LocalDate(-10, 1, 5).format { byUnicodeFormat("yyyy-MM-dd") } // -0010-01-05
 94â†’ * LocalDate(-10, 1, 5).toJavaLocalDate().format(java.time.format.DateTimeFormatter.ofPattern("yyyy-MM-dd")) // 0011-01-05
 95â†’ * ```
 96â†’ *
 97â†’ * Note that, when the format includes the era directive, [byUnicodePattern] will fail with an exception, so almost all
 98â†’ * of the intentional usages of `y` will correctly report an error instead of behaving slightly differently.
 99â†’ *
100â†’ * @throws IllegalArgumentException if the pattern is invalid or contains unsupported directives.
101â†’ * @throws IllegalArgumentException if the builder is incompatible with the specified directives.
102â†’ * @throws UnsupportedOperationException if the kotlinx-datetime library does not support the specified directives.
103â†’ */
104â†’@FormatStringsInDatetimeFormats
105â†’public fun DateTimeFormatBuilder.byUnicodePattern(pattern: String) {
106â†’    val directives = UnicodeFormat.parse(pattern)
107â†’    fun rec(builder: DateTimeFormatBuilder, format: UnicodeFormat) {
108â†’        when (format) {
109â†’            is UnicodeFormat.StringLiteral -> builder.chars(format.literal)
110â†’            is UnicodeFormat.Sequence -> format.formats.forEach { rec(builder, it) }
111â†’            is UnicodeFormat.OptionalGroup -> builder.alternativeParsing({}) {
112â†’                rec(this, format.format)
113â†’            }
114â†’            is UnicodeFormat.Directive -> {
115â†’                when (format) {
116â†’                    is UnicodeFormat.Directive.TimeBased -> {
117â†’                        require(builder is DateTimeFormatBuilder.WithTime) {
118â†’                            "A time-based directive $format was used in a format builder that doesn't support time components"
119â†’                        }
120â†’                        format.addToFormat(builder)
121â†’                    }
122â†’
123â†’                    is UnicodeFormat.Directive.DateBased -> {
124â†’                        require(builder is DateTimeFormatBuilder.WithDate) {
125â†’                            "A date-based directive $format was used in a format builder that doesn't support date components"
126â†’                        }
127â†’                        format.addToFormat(builder)
128â†’                    }
129â†’
130â†’                    is UnicodeFormat.Directive.ZoneBased -> {
131â†’                        require(builder is DateTimeFormatBuilder.WithDateTimeComponents) {
132â†’                            "A time-zone-based directive $format was used in a format builder that doesn't support time-zone components"
133â†’                        }
134â†’                        format.addToFormat(builder)
135â†’                    }
136â†’
137â†’                    is UnicodeFormat.Directive.OffsetBased -> {
138â†’                        require(builder is DateTimeFormatBuilder.WithUtcOffset) {
139â†’                            "A UTC-offset-based directive $format was used in a format builder that doesn't support UTC offset components"
140â†’                        }
141â†’                        format.addToFormat(builder)
142â†’                    }
143â†’
144â†’                    is UnknownUnicodeDirective -> {
145â†’                        throw IllegalArgumentException("The meaning of the directive '$format' is unknown")
146â†’                    }
147â†’                }
148â†’            }
149â†’        }
150â†’    }
151â†’    rec(this, directives)
152â†’}
