242â†’        override fun equals(other: Any?): Boolean =
243â†’            other is Directive && formatLetter == other.formatLetter && formatLength == other.formatLength
244â†’
245â†’        override fun hashCode(): Int = formatLetter.hashCode() * 31 + formatLength
