 90â†’ * This may lead to unexpected results if the year is negative: `y` would always produce a positive number, whereas
 91â†’ * `u` may sometimes produce a negative one. For example:
 92â†’ * ```
 93â†’ * LocalDate(-10, 1, 5).format { byUnicodeFormat("yyyy-MM-dd") } // -0010-01-05
 94â†’ * LocalDate(-10, 1, 5).toJavaLocalDate().format(java.time.format.DateTimeFormatter.ofPattern("yyyy-MM-dd")) // 0011-01-05
 95â†’ * ```
 96â†’ *
 97â†’ * Note that, when the format includes the era directive, [byUnicodePattern] will fail with an exception, so almost all
 98â†’ * of the intentional usages of `y` will correctly report an error instead of behaving slightly differently.
 99â†’ *
100â†’ * @throws IllegalArgumentException if the pattern is invalid or contains unsupported directives.
101â†’ * @throws IllegalArgumentException if the builder is incompatible with the specified directives.
102â†’ * @throws UnsupportedOperationException if the kotlinx-datetime library does not support the specified directives.
103â†’ */
104â†’@FormatStringsInDatetimeFormats
105â†’public fun DateTimeFormatBuilder.byUnicodePattern(pattern: String) {
106â†’    val directives = UnicodeFormat.parse(pattern)
107â†’    fun rec(builder: DateTimeFormatBuilder, format: UnicodeFormat) {
108â†’        when (format) {
109â†’            is UnicodeFormat.StringLiteral -> builder.chars(format.literal)
110â†’            is UnicodeFormat.Sequence -> format.formats.forEach { rec(builder, it) }
111â†’            is UnicodeFormat.OptionalGroup -> builder.alternativeParsing({}) {
112â†’                rec(this, format.format)
113â†’            }
114â†’            is UnicodeFormat.Directive -> {
115â†’                when (format) {
116â†’                    is UnicodeFormat.Directive.TimeBased -> {
117â†’                        require(builder is DateTimeFormatBuilder.WithTime) {
118â†’                            "A time-based directive $format was used in a format builder that doesn't support time components"
119â†’                        }
120â†’                        format.addToFormat(builder)
121â†’                    }
122â†’
123â†’                    is UnicodeFormat.Directive.DateBased -> {
124â†’                        require(builder is DateTimeFormatBuilder.WithDate) {
125â†’                            "A date-based directive $format was used in a format builder that doesn't support date components"
126â†’                        }
127â†’                        format.addToFormat(builder)
128â†’                    }
129â†’
130â†’                    is UnicodeFormat.Directive.ZoneBased -> {
131â†’                        require(builder is DateTimeFormatBuilder.WithDateTimeComponents) {
132â†’                            "A time-zone-based directive $format was used in a format builder that doesn't support time-zone components"
133â†’                        }
134â†’                        format.addToFormat(builder)
135â†’                    }
136â†’
137â†’                    is UnicodeFormat.Directive.OffsetBased -> {
138â†’                        require(builder is DateTimeFormatBuilder.WithUtcOffset) {
139â†’                            "A UTC-offset-based directive $format was used in a format builder that doesn't support UTC offset components"
140â†’                        }
141â†’                        format.addToFormat(builder)
142â†’                    }
143â†’
144â†’                    is UnknownUnicodeDirective -> {
145â†’                        throw IllegalArgumentException("The meaning of the directive '$format' is unknown")
146â†’                    }
147â†’                }
148â†’            }
149â†’        }
150â†’    }
151â†’    rec(this, directives)
152â†’}
