154â†’/*
155â†’The code that translates Unicode directives to the kotlinx-datetime format is based on these references:
156â†’* https://docs.oracle.com/en/java/javase/16/docs/api/java.base/java/time/format/DateTimeFormatterBuilder.html#appendPattern(java.lang.String)
157â†’* https://unicode-org.github.io/icu/userguide/format_parse/datetime/#datetime-format-syntax
158â†’ */
159â†’internal sealed interface UnicodeFormat {
160â†’    companion object {
161â†’        fun parse(pattern: String): UnicodeFormat {
162â†’            val groups: MutableList<MutableList<UnicodeFormat>?> = mutableListOf(mutableListOf())
163â†’            var insideLiteral = false
164â†’            var literal = ""
165â†’            var lastCharacter: Char? = null
166â†’            var lastCharacterCount = 0
167â†’            for (character in pattern) {
168â†’                if (character == lastCharacter) {
169â†’                    ++lastCharacterCount
170â†’                } else if (insideLiteral) {
171â†’                    if (character == '\'') {
172â†’                        groups.last()?.add(StringLiteral(literal.ifEmpty { "'" }))
173â†’                        insideLiteral = false
174â†’                        literal = ""
175â†’                    } else literal += character
176â†’                } else {
177â†’                    if (lastCharacterCount > 0) {
178â†’                        groups.last()?.add(unicodeDirective(lastCharacter!!, lastCharacterCount))
179â†’                        lastCharacter = null
180â†’                        lastCharacterCount = 0
181â†’                    }
182â†’                    if (character !in nonPlainCharacters) {
183â†’                        literal += character
184â†’                        continue
185â†’                    }
186â†’                    if (literal != "") {
187â†’                        groups.last()?.add(StringLiteral(literal))
188â†’                        literal = ""
189â†’                    }
190â†’                    when (character) {
191â†’                        '\'' -> {
192â†’                            insideLiteral = true
193â†’                            literal = ""
194â†’                        }
195â†’
196â†’                        '[' -> {
197â†’                            groups.add(mutableListOf())
198â†’                        }
199â†’
200â†’                        ']' -> {
201â†’                            val group =
202â†’                                groups.removeLast() ?: throw IllegalArgumentException("Unmatched closing bracket")
203â†’                            groups.last()?.add(OptionalGroup(Sequence(group)))
204â†’                        }
205â†’
206â†’                        else -> {
207â†’                            lastCharacter = character
208â†’                            lastCharacterCount = 1
209â†’                        }
210â†’                    }
211â†’                }
212â†’            }
213â†’            if (lastCharacterCount > 0) {
214â†’                groups.last()?.add(unicodeDirective(lastCharacter!!, lastCharacterCount))
215â†’            }
216â†’            if (literal != "") {
217â†’                groups.last()?.add(StringLiteral(literal))
218â†’            }
219â†’            return Sequence(groups.removeLast() ?: throw IllegalArgumentException("Unmatched opening bracket"))
220â†’        }
221â†’    }
